    from_domains_ref?: {
      source_group: string;
      confidence: string;
    };
    subject_prefixes?: string[];
    from_addresses?: string[];
  };
  strong_indicators: {
    from_domains_ref?: {
      source_group: string;
      confidence: string;
    };
    subject_contains?: string[];
    body_contains?: string[];
  };
