const fs = require('fs');

// Read the config file
const configPath = '/workspaces/gmail-automation/config/email-categorizer-config.json';
const config = JSON.parse(fs.readFileSync(configPath, 'utf8'));

// Function to convert snake_case to camelCase
function toCamelCase(str) {
  return str.replace(/_([a-z])/g, (_, letter) => letter.toUpperCase());
}

// Recursively transform all keys in an object
function transformKeys(obj) {
  if (Array.isArray(obj)) {
    return obj.map(transformKeys);
  } else if (obj !== null && typeof obj === 'object') {
    return Object.keys(obj).reduce((result, key) => {
      const newKey = toCamelCase(key);
      result[newKey] = transformKeys(obj[key]);
      return result;
    }, {});
  }
  return obj;
}

// Transform the config
const transformed = transformKeys(config);

// Write back to file
fs.writeFileSync(configPath, JSON.stringify(transformed, null, 2) + '\n', 'utf8');

console.log('Config file transformed successfully');
console.log('Total keys transformed: ' + JSON.stringify(config).match(/"[a-z_]+"\s*:/g).length);
EOF
