});

// Function to transform TypeScript file
function transformTypeScriptFile(content) {
  let result = content;

  // Transform interface property names (but not in strings)
  Object.keys(mapping).forEach(snake => {
    const camel = mapping[snake];

    // Match property declarations in interfaces and type definitions
    // Pattern: optional whitespace, property name, optional ?, colon
    const propertyRegex = new RegExp(`(\\s+)${snake}(\\??\\s*:)`, 'g');
    result = result.replace(propertyRegex, `$1${camel}$2`);

