    // Match bracket notation access (but preserve string literals)
    // Only transform if it's an identifier, not a string
    const bracketRegex = new RegExp(`\\['${snake}'\\]`, 'g');
    result = result.replace(bracketRegex, `['${camel}']`);
  });

  return result;
}

