          urgent_indicator: 'DISAMBIGUATOR',
        },
      };

      executeDisambiguation(mockEmail, session, result, mockConfig);

      // Should use previous influence applications in disambiguation
      expect(result.scoreBreakdown.disambiguationApplied.length).toBeGreaterThanOrEqual(0);
    });

    test('should preserve stage chain data', () => {
      const { session, result } = setupTest({
        FINANCIAL: 12,
        PERSONAL: 11,
      });

